import React from 'react';
import { ChevronRight } from 'lucide-react';
import { MessageItem } from '../types';
import MessageItemComponent from './MessageItem';

interface MessageListProps {
  items: MessageItem[];
  selectedIds: number[];
  setSelectedIds: (ids: number[] | ((prev: number[]) => number[])) => void;
  loading: boolean;
  selectedSubMenuId: number | null;
  theme: 'light' | 'dark';
  empty: string;
  noItems: string;
}

const MessageList: React.FC<MessageListProps> = ({ 
  items, 
  selectedIds, 
  setSelectedIds, 
  loading, 
  selectedSubMenuId, 
  theme, 
  empty, 
  noItems 
}) => {
  const isAnySelected = selectedIds.length > 0;

  return (
    <div className="flex-1 overflow-y-auto relative p-4">
      {loading ? (
        <div className="flex flex-col items-center justify-center h-full opacity-50 space-y-4">
          <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
        </div>
      ) : selectedSubMenuId === null ? (
        <div className="flex flex-col items-center justify-center h-full opacity-40 text-center p-8">
          <div className="w-24 h-24 mb-4 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center">
             <ChevronRight size={48} />
          </div>
          <p className="text-lg font-medium">{empty}</p>
        </div>
      ) : items.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-full opacity-40">
          <p>{noItems}</p>
        </div>
      ) : (
        <div className="max-w-5xl mx-auto space-y-1">
          {items.map((item) => (
            <MessageItemComponent
              key={item.id}
              item={item}
              selectedIds={selectedIds}
              setSelectedIds={setSelectedIds}
              isAnySelected={isAnySelected}
              theme={theme}
            />
          ))}
          <p className="text-sm text-gray-500">
            Selecione um menu na barra lateral para ver os itens disponíveis.
          </p>
        </div>
      )}
    </div>
  );
};

export default MessageList;
